import{_ as n,o as e,c as o,ag as r}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"01 — Tầm nhìn sản phẩm","description":"","frontmatter":{},"headers":[],"relativePath":"00-san-pham/01-tam-nhin.md","filePath":"00-san-pham/01-tam-nhin.md"}'),a={name:"00-san-pham/01-tam-nhin.md"};function h(d,t,i,c,l,s){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="_01-—-tam-nhin-san-pham" tabindex="-1">01 — Tầm nhìn sản phẩm <a class="header-anchor" href="#_01-—-tam-nhin-san-pham" aria-label="Permalink to &quot;01 — Tầm nhìn sản phẩm&quot;">​</a></h1><blockquote><p><strong>Vai trò đọc</strong>: PO, PM, Founder, Tech Lead — bất kỳ ai muốn hiểu <strong>vì sao</strong> dự án này tồn tại trước khi xem code/schema. <strong>Quy tắc cập nhật</strong>: chỉ sửa khi có pivot business thật (Founder duyệt). Mọi thay đổi log vào <code>99-tham-khao/changelog.md</code>.</p></blockquote><hr><h2 id="why-—-vi-sao-vivu-ton-tai" tabindex="-1">WHY — Vì sao Vivu tồn tại <a class="header-anchor" href="#why-—-vi-sao-vivu-ton-tai" aria-label="Permalink to &quot;WHY — Vì sao Vivu tồn tại&quot;">​</a></h2><p>Người Việt đặt tour du lịch B2C đang kẹt giữa 2 cực:</p><ul><li><strong>Facebook/Zalo + operator nhỏ lẻ</strong>: không minh bạch giá, không có review độc lập, mô tả lịch trình rời rạc qua tin nhắn, chuyển khoản tay → khó kiểm chứng chất lượng trước khi đi.</li><li><strong>Sàn quốc tế (Traveloka, Klook, Agoda)</strong>: nghiêng về tour chuẩn hoá quốc tế, thiếu tour local đặc trưng Việt Nam (homestay vùng cao, foodtour địa phương), trải nghiệm tiếng Việt còn cứng.</li></ul><p><strong>Vivu lấp khoảng giữa</strong>: tour B2C minh bạch về giá / lịch trình / đánh giá, đặt online 24/7, do người Việt vận hành cho khách Việt.</p><hr><h2 id="who-—-khach-hang-muc-tieu" tabindex="-1">WHO — Khách hàng mục tiêu <a class="header-anchor" href="#who-—-khach-hang-muc-tieu" aria-label="Permalink to &quot;WHO — Khách hàng mục tiêu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Nhóm</th><th>Mô tả ngắn</th><th>Phase tập trung</th></tr></thead><tbody><tr><td><strong>B2C primary</strong></td><td>Người Việt 25-45 tuổi, thu nhập trung-cao, đi gia đình / cặp đôi / nhóm bạn.</td><td>Phase 1</td></tr><tr><td><strong>B2C secondary</strong></td><td>Khách quốc tế tới Việt Nam (landing EN).</td><td>Phase 1.5</td></tr><tr><td><strong>Admin nội bộ</strong></td><td>Operator Vivu — quản inventory, đẩy promotion, theo dõi đơn.</td><td>Phase 1</td></tr></tbody></table><p>→ Chi tiết 3 personas xem <code>03-personas-user-journey.md</code>.</p><hr><h2 id="what-—-san-pham-cu-the" tabindex="-1">WHAT — Sản phẩm cụ thể <a class="header-anchor" href="#what-—-san-pham-cu-the" aria-label="Permalink to &quot;WHAT — Sản phẩm cụ thể&quot;">​</a></h2><p>Vivu = <strong>tour operator B2C trực tuyến</strong>, tự cung cấp tour (không marketplace, không affiliate).</p><p><strong>Phase 1 (MVP, 3–6 tháng):</strong></p><table tabindex="0"><thead><tr><th>Module</th><th style="text-align:center;">Có ở MVP?</th><th>Tóm tắt</th></tr></thead><tbody><tr><td>Tour browse + filter + detail</td><td style="text-align:center;">✅</td><td>List/filter/detail có gallery + itinerary</td></tr><tr><td>Tour booking + thanh toán</td><td style="text-align:center;">✅</td><td>VNPay/MoMo, bắt buộc login, snapshot pricing</td></tr><tr><td>Tour departure &amp; inventory</td><td style="text-align:center;">✅</td><td>Lịch khởi hành, slot, anti-overbook</td></tr><tr><td>Hotel info trong tour combo</td><td style="text-align:center;">✅</td><td>Content reference, không book riêng</td></tr><tr><td>Auth khách hàng</td><td style="text-align:center;">✅</td><td>Email + Google OAuth, dual cookie admin/public</td></tr><tr><td>Review tour</td><td style="text-align:center;">✅</td><td>Khách đã hoàn thành tour mới review</td></tr><tr><td>SEO foundation</td><td style="text-align:center;">✅</td><td>Sitemap động + structured data + metadata override</td></tr><tr><td>Admin CMS</td><td style="text-align:center;">✅</td><td>Tour, destination, hotel, booking, settings, audit log</td></tr><tr><td>Admin Dashboard L0 (Operational)</td><td style="text-align:center;">✅</td><td>Đơn hôm nay, doanh thu tuần, top tour, export CSV</td></tr><tr><td>Tour pricing + upsell options</td><td style="text-align:center;">✅</td><td>Per-pax + TourOption (room upgrade, single supplement…)</td></tr><tr><td>Private Tour Lead Capture</td><td style="text-align:center;">✅</td><td>Form &quot;Đặt nhóm riêng&quot; → admin liên hệ quote manual</td></tr><tr><td>Hotel allotment monthly tracking</td><td style="text-align:center;">✅</td><td>Admin nhập tay đầu tháng — không per-date</td></tr><tr><td>Booking payment hold 15 phút</td><td style="text-align:center;">✅</td><td>PENDING + cron auto-cancel + release slot</td></tr><tr><td>Tour policy structured</td><td style="text-align:center;">✅</td><td>JSON + Zod: trẻ em, cancellation tier, inclusions</td></tr><tr><td>i18n VI/EN</td><td style="text-align:center;">✅</td><td>next-intl từ ngày 1</td></tr></tbody></table><p>Phase 1 <strong>cố ý không có</strong> — xem mục Non-Goals.</p><hr><h2 id="how-—-mo-hinh-van-hanh-doanh-thu" tabindex="-1">HOW — Mô hình vận hành &amp; doanh thu <a class="header-anchor" href="#how-—-mo-hinh-van-hanh-doanh-thu" aria-label="Permalink to &quot;HOW — Mô hình vận hành &amp; doanh thu&quot;">​</a></h2><ul><li>Vivu là <strong>tour operator trực tiếp</strong>: tự ký contract hotel/transport/guide → đóng gói tour → bán cho khách cuối.</li><li><strong>Không trung gian</strong>: không marketplace, không commission split.</li><li><strong>Hotel</strong> chỉ là content reference: Vivu contract trước (allotment monthly), bán tour thì block phòng đã giữ. Customer không &quot;chọn hotel&quot; — hotel là attribute của package.</li><li><strong>Doanh thu</strong> Phase 1 = markup (giá bán − giá vốn). Phase 1.5+ thêm upsell. Phase 2+ thêm affiliate KOL.</li></ul><p>→ Chi tiết kinh tế đơn hàng + KPI: <code>02-mo-hinh-kinh-doanh.md</code>.</p><hr><h2 id="where-—-thi-truong-ngon-ngu" tabindex="-1">WHERE — Thị trường &amp; ngôn ngữ <a class="header-anchor" href="#where-—-thi-truong-ngon-ngu" aria-label="Permalink to &quot;WHERE — Thị trường &amp; ngôn ngữ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Khía cạnh</th><th>Phase 1</th><th>Phase 1.5</th><th>Phase 2</th></tr></thead><tbody><tr><td>Địa lý</td><td>Việt Nam (3 miền)</td><td>+ landing EN</td><td>Mở rộng nội địa sâu hơn</td></tr><tr><td>Ngôn ngữ</td><td>VI chính + EN khung</td><td>EN đầy đủ tour quốc tế</td><td>Cân nhắc CN/JP</td></tr><tr><td>Tiền tệ</td><td>VND only</td><td>VND + USD hint</td><td>Cân nhắc multi-currency</td></tr></tbody></table><hr><h2 id="when-—-lo-trinh-tong" tabindex="-1">WHEN — Lộ trình tổng <a class="header-anchor" href="#when-—-lo-trinh-tong" aria-label="Permalink to &quot;WHEN — Lộ trình tổng&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Thời gian</th><th>Mục tiêu</th></tr></thead><tbody><tr><td><strong>Phase 1 MVP</strong></td><td>Q2–Q3/2026</td><td>Tour book + pay + CMS + SEO; launch private beta</td></tr><tr><td><strong>Phase 1.5</strong></td><td>Q4/2026</td><td>EN landing, loyalty cơ bản, upsell</td></tr><tr><td><strong>Phase 2</strong></td><td>2027</td><td>Affiliate KOL, mobile RN, tinh chỉnh inventory</td></tr><tr><td><strong>Phase 3+</strong></td><td>2028+</td><td>Hotel portal lite, đa thị trường — chưa commit</td></tr></tbody></table><p>→ Sprint mapping chi tiết: <code>04-lo-trinh-phat-hanh.md</code>.</p><hr><h2 id="non-goals-—-cai-co-y-khong-lam-phase-1" tabindex="-1">Non-Goals — Cái cố ý KHÔNG làm Phase 1 <a class="header-anchor" href="#non-goals-—-cai-co-y-khong-lam-phase-1" aria-label="Permalink to &quot;Non-Goals — Cái cố ý KHÔNG làm Phase 1&quot;">​</a></h2><blockquote><p>Scope creep là kẻ thù số 1. Mỗi PR/sprint mới phải check: feature này có rơi vào Non-Goals không? Nếu có → escalate trước khi commit.</p></blockquote><table tabindex="0"><thead><tr><th>Cái KHÔNG làm</th><th>Lý do ngắn</th></tr></thead><tbody><tr><td><strong>Marketplace</strong> (operator khác list tour)</td><td>Vivu là operator trực tiếp, không phải sàn. Build marketplace confuse brand + tăng auth surface 3x.</td></tr><tr><td><strong>Hotel booking độc lập</strong></td><td>Phase 1 + 2 đều không. Vivu không trở thành OTA hotel. → ADR-001.</td></tr><tr><td><strong>Hotel supplier portal</strong></td><td>Inventory hotel là việc của hotel. Vivu contract allotment trước — như cách industry làm.</td></tr><tr><td><strong>Mobile native app</strong></td><td>Web responsive đủ cho MVP. Mobile chỉ làm khi data chứng minh retention.</td></tr><tr><td><strong>Guest checkout</strong> (book không login)</td><td>Bắt buộc login → loyalty + giảm fake + dễ dispute. → ADR-004.</td></tr><tr><td><strong>Multi-currency / Stripe quốc tế</strong></td><td>Phase 1 chỉ VND + VNPay/MoMo.</td></tr><tr><td><strong>Loyalty system chính thức</strong></td><td>Phase 1.5 sau khi có user base.</td></tr><tr><td><strong>Live chat / chatbot AI</strong></td><td>Phase 2. MVP dùng email + hotline.</td></tr><tr><td><strong>Multi-tenant admin</strong></td><td>Vivu single brand. Multi chỉ Phase 3 nếu acquire công ty khác.</td></tr><tr><td><strong>Public REST API mở</strong></td><td><code>/api/v1/*</code> chỉ internal. Không dev portal Phase 1.</td></tr><tr><td><strong>Admin Dashboard L1/L2</strong></td><td>L0 (operational) đủ Phase 1. L1 conversion 1.5. L2 P&amp;L Phase 2 hoặc Excel + kế toán.</td></tr></tbody></table><hr><h2 id="quyet-đinh-goc-—-trace-ve-adr" tabindex="-1">Quyết định gốc — trace về ADR <a class="header-anchor" href="#quyet-đinh-goc-—-trace-ve-adr" aria-label="Permalink to &quot;Quyết định gốc — trace về ADR&quot;">​</a></h2><p>Mọi quyết định technical phải trace về 1 trong các ADR sau (folder <code>02-kien-truc/decisions/</code>):</p><table tabindex="0"><thead><tr><th>ADR</th><th>Quyết định</th><th>Status</th></tr></thead><tbody><tr><td><strong>ADR-001</strong></td><td>Hotel = Content Reference vĩnh viễn (cả Phase 2) — DROP <code>HotelBooking</code> + <code>bookingType</code></td><td>Accepted</td></tr><tr><td><strong>ADR-002</strong></td><td>Pricing Pattern C: per-pax + service tier upsell (<code>TourOption</code>)</td><td>Accepted</td></tr><tr><td><strong>ADR-003</strong></td><td>UUID native type cho toàn schema (<code>@db.Uuid</code>) — fix TEXT mismatch</td><td>Accepted (PART 0 migration)</td></tr><tr><td><strong>ADR-004</strong></td><td>Must-login để book — không guest checkout</td><td>Accepted</td></tr><tr><td><strong>ADR-005</strong></td><td>SEO-first acquisition: <code>SeoPage</code> polymorphic + sitemap động + Next.js metadata</td><td>Accepted</td></tr><tr><td><strong>ADR-006</strong></td><td>Series + Private Tour split — <code>TourDeparture</code> (online) vs <code>InquiryRequest</code> (lead capture)</td><td>Accepted</td></tr><tr><td><strong>ADR-007</strong></td><td>Admin Reporting 3 tier L0/L1/L2 — Phase 1 chỉ L0; schema chừa cửa cost tracking</td><td>Accepted</td></tr></tbody></table><p>→ Folder ADR sẽ fill ở D4/D5.</p><hr><h2 id="quy-tac-dung-file-nay" tabindex="-1">Quy tắc dùng file này <a class="header-anchor" href="#quy-tac-dung-file-nay" aria-label="Permalink to &quot;Quy tắc dùng file này&quot;">​</a></h2><ol><li><strong>Vision = constitution</strong>. Không sửa khi có biến động nhỏ. Chỉ sửa khi pivot business thật.</li><li><strong>Mọi quyết định technical trace về ADR</strong> (không phải V-XX cũ — đã deprecated).</li><li><strong>Non-Goals quan trọng ngang Goals</strong>. Mỗi sprint mới phải check.</li><li><strong>Update định kỳ</strong>: review 1 lần/quý. Mọi thay đổi log vào <code>99-tham-khao/changelog.md</code>.</li></ol><hr><h2 id="lien-ket" tabindex="-1">Liên kết <a class="header-anchor" href="#lien-ket" aria-label="Permalink to &quot;Liên kết&quot;">​</a></h2><ul><li>Mô hình kinh doanh: <code>02-mo-hinh-kinh-doanh.md</code></li><li>Personas + journey: <code>03-personas-user-journey.md</code></li><li>Lộ trình sprint: <code>04-lo-trinh-phat-hanh.md</code></li><li>ADR folder: <code>../02-kien-truc/decisions/</code></li><li>Doc cũ (V-XX anchors): <code>../99-tham-khao/archive/01-nen-tang-he-thong/00-tam-nhin.md</code></li></ul>',43)])])}const p=n(a,[["render",h]]);export{u as __pageData,p as default};
